import React from "react";
import { makeStyles } from "@material-ui/core/styles";
import CssBaseline from "@material-ui/core/CssBaseline";
import { Redirect, useHistory } from "react-router-dom";
import { BrowserRouter as Router, Switch, Route } from "react-router-dom";
import { useRecoilState } from "recoil";
import { Flex } from "@chakra-ui/react";
// import Chart from "./Chart";
// import Deposits from "./Deposits";
// import Orders from "./Orders";

import Appbanner from "./Appbanner";
//import Example from "./Example6";
//import SideDrawer from "./SideDrawer";
//import SingleEmployee from "./SingleEmployee";
//import SingleLeave from "./SingleLeave";
//import SingleExpense from "./SingleExpense";
//import SingleDailyAllowance from "./SingleDailyAllowance";
//import SingleDailyAllowsDetls from "./SingleDailyAllowsDetls";
//import BatchDailyAllowances from "./BatchDailyAllowances";
//import SinglePayslip from "./SinglePayslip";
import { loginLevelState } from "./data/atomdata";
import Login from "./LoginForm";
//import Payrun from "./Payrun";
//import Payrunbatch from "./Payrunbatch";
import DashboardStaff from "./DashboardStaff";
import DashboardAdmin from "./DashboardAdmin";
import DashboardOpsSpvr from "./DashboardOpsSpvr";
import DashboardAdminManager from "./DashboardAdminManager";
import DashboardManager from "./DashboardManager";
import DashboardDirector from "./DashboardDirector";
//import SingleEmployeeStaff from "./SingleEmployeeStaff";
//import SingleDailyAllowsDetlsStaff from "./SingleDailyAllowsDetlsStaff";

import {
  Home,
  AllEmployees,
  Leave,
  DailyAllowancesStaff,
  Expenses,
  Hoc,
  LeaveStaff,
  Payslip,
  BatchPayslips,
  Payroll,
  PayslipStaff,
  TrainingsStaff,
  ExpensesStaff,
  Departments,
  Designation,
  Tables,
  Clients,
  Allowances,
  DailyAllowances,
  PrivateRoute,
  Error
} from
"../pages";

const drawerWidth = 0;

export default function DashboardMain() {
  const classes = useStyles();
  const history = useHistory();
  const [loginLevel, setLoginLevel] = useRecoilState(loginLevelState);
  const [open, setOpen] = React.useState(true);
  const [login, setLogin] = React.useState(true);
  const [select, setSelect] = React.useState("Staff");
  //console.log("loginLevel", loginLevel);

  const handleDrawerOpen = () => {
    setOpen(true);
  };
  const handleDrawerClose = () => {
    setOpen(false);
  };

  const handleSelect = (title) => {
    setLoginLevel({ ...loginLevel, loginLevel: title });
    setSelect(title);
    <Redirect to="/" />;
  };

  //  const fixedHeightPaper = clsx(classes.paper, classes.fixedHeight);

  if (!login) {
    return <Login setLogin={setLogin} />;
  }
  return (
    <div className={classes.root}>
      <CssBaseline />
      <Router>
        <Appbanner
          handleDrawerOpen={handleDrawerOpen}
          handleDrawerClose={handleDrawerClose}
          handleSelect={handleSelect}
          open={open}
          setLogin={setLogin}
          title="HRMS V1.5 - AppSmiths Sutera Sdn Bhd"
        />
        <SideDrawer
          handleDrawerOpen={handleDrawerOpen}
          handleDrawerClose={handleDrawerClose}
          open={open}
        />
        <Flex>
          {select === "Staff" && (
            // <DashboardStaff
            //   open={open}
            //   handleDrawerOpen={handleDrawerOpen}
            //   handleDrawerClose={handleDrawerClose}
            // />
            <Switch>
              <Route exact path="/">
                <Home />
              </Route>
              {/* <Route exact path="/home">
              <Home />
            </Route> */}
              {/* <Route exact path="/allemployees">
              <AllEmployees />
            </Route> */}
              <Route exact path="/payroll">
                <Payroll />
              </Route>
              <Route exact path="/payslips">
                <PayslipStaff />
              </Route>
              <Route exact path="/singlepayslip">
                <SinglePayslip />
              </Route>
              <Route exact path="/batchpayslips">
                <BatchPayslips />
              </Route>
              <Route exact path="/leave">
                <LeaveStaff />
              </Route>
              <Route exact path="/hoc">
                <Hoc />
              </Route>
              <Route exact path="/trainings">
                <TrainingsStaff />
              </Route>
              {/* <Route exact path="/payrun">
              <Payrun />
            </Route> */}
              {/* <Route exact path="/payrunbatch">
              <Payrunbatch />
            </Route> */}
              <Route exact path="/dailyallowances">
                <DailyAllowancesStaff />
              </Route>
              <Route exact path="/singledailyallowsdetlstable">
                <SingleDailyAllowsDetlsStaff />
              </Route>
              <Route exact path="/expenses">
                <ExpensesStaff />
              </Route>
              {/* <Route exact path="/departments">
              <Departments />
            </Route>
            <Route exact path="/designation">
              <Designation />
            </Route>
            <Route exact path="/tables">
              <Tables />
            </Route>
            <Route exact path="/allowances">
              <Allowances />
            </Route>
            <Route exact path="/clients">
              <Clients />
            </Route> */}
              <Route exact path="/example">
                <Example />
              </Route>
              <Route exact path="/singleemployee">
                <SingleEmployeeStaff />
              </Route>
              <Route exact path="/singleleave">
                <SingleLeave />
              </Route>
              <Route exact path="/singleexpense">
                <SingleExpense />
              </Route>
              <Route exact path="/singledailyallowance">
                <SingleDailyAllowance />
              </Route>
              <Route exact path="/batchdailyallowances">
                <BatchDailyAllowances />
              </Route>
              <Route exact path="/error">
                <Error />
              </Route>
              {/* <Route
              exact
              path="/employees/:empId"
              children={<SingleEmployee />}
            /> */}
              <Route path="*">
                <Error />
              </Route>
            </Switch>
          )}
          {select === "Admin" && (
            <DashboardAdmin
              open={open}
              handleDrawerOpen={handleDrawerOpen}
              handleDrawerClose={handleDrawerClose}
            />
          )}
          {select === "OpsSpvr" && (
            <DashboardOpsSpvr
              open={open}
              handleDrawerOpen={handleDrawerOpen}
              handleDrawerClose={handleDrawerClose}
            />
          )}
          {select === "AdminManager" && (
            <DashboardAdminManager
              open={open}
              handleDrawerOpen={handleDrawerOpen}
              handleDrawerClose={handleDrawerClose}
            />
          )}
          {select === "Manager" && (
            <DashboardManager
              open={open}
              handleDrawerOpen={handleDrawerOpen}
              handleDrawerClose={handleDrawerClose}
            />
          )}
          {select === "Director" && (
            <DashboardDirector
              open={open}
              handleDrawerOpen={handleDrawerOpen}
              handleDrawerClose={handleDrawerClose}
            />
          )}
        </Flex>
      </Router>
    </div>
  );
}

const useStyles = makeStyles((theme) => ({
  root: {
    display: "flex",
  },
  toolbar: {
    paddingRight: 24, // keep right padding when drawer closed
  },
  toolbarIcon: {
    display: "flex",
    alignItems: "center",
    justifyContent: "flex-end",
    padding: "0 8px",
    ...theme.mixins.toolbar,
  },
  appBar: {
    zIndex: theme.zIndex.drawer + 1,
    transition: theme.transitions.create(["width", "margin"], {
      easing: theme.transitions.easing.sharp,
      duration: theme.transitions.duration.leavingScreen,
    }),
  },
  appBarShift: {
    marginLeft: drawerWidth,
    width: `calc(100% - ${drawerWidth}px)`,
    transition: theme.transitions.create(["width", "margin"], {
      easing: theme.transitions.easing.sharp,
      duration: theme.transitions.duration.enteringScreen,
    }),
  },
  menuButton: {
    marginRight: 36,
  },
  menuButtonHidden: {
    display: "none",
  },
  title: {
    flexGrow: 1,
  },
  drawerPaper: {
    position: "relative",
    whiteSpace: "nowrap",
    width: drawerWidth,
    transition: theme.transitions.create("width", {
      easing: theme.transitions.easing.sharp,
      duration: theme.transitions.duration.enteringScreen,
    }),
  },
  drawerPaperClose: {
    overflowX: "hidden",
    transition: theme.transitions.create("width", {
      easing: theme.transitions.easing.sharp,
      duration: theme.transitions.duration.leavingScreen,
    }),
    width: theme.spacing(7),
    [theme.breakpoints.up("sm")]: {
      width: theme.spacing(9),
    },
  },
